         PairwiseMagnitude.MuchBetter => 1.0,
         PairwiseMagnitude.SlightlyBetter => 0.4,
         PairwiseMagnitude.Equal => 0.0,
         PairwiseMagnitude.SlightlyWorse => -0.4,
         PairwiseMagnitude.MuchWorse => -1.0,
         _ => 0.0,
     };
 }

 public enum JudgeMode
 {
     Pairwise,
     Independent,
     Both,
 }

